"use client";

/* ════════════════════════════════════════════════════════════════════════
   BridgeHome — the Operations Bridge home surface.
   AI strip (3 cards + 9 expandable rows) + Quick Actions grid (8 verbs).
   ════════════════════════════════════════════════════════════════════════ */

import { useState } from "react";
import { useBridge, type BridgePage } from "@/features/bridge/hooks/use-bridge";
import {
  opsBridgeCards,
  opsBridgeRows,
  opsBridgeMeta,
  type RiskLevel,
} from "@/features/ops/api/ops-bridge-data";

const RISK_CLASS: Record<RiskLevel, string> = {
  low: "",
  medium: " med",
  high: " high",
};

/* ─────────────── Quick Action icons ─────────────── */
const ACTION_ICONS: Record<string, React.ReactNode> = {
  "new-item": (
    <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.6">
      <path d="M12 2 L21 7 L21 17 L12 22 L3 17 L3 7 Z" />
      <path d="M3 7 L12 12 L21 7" />
      <line x1="12" y1="12" x2="12" y2="22" />
    </svg>
  ),
  "add-category": (
    <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.6">
      <rect x="3" y="3" width="7" height="7" />
      <rect x="14" y="3" width="7" height="7" />
      <rect x="3" y="14" width="7" height="7" />
      <rect x="14" y="14" width="7" height="7" />
    </svg>
  ),
  "add-supplier": (
    <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.6">
      <path d="M3 21 L3 8 L12 3 L21 8 L21 21" />
      <path d="M3 21 L21 21" />
      <rect x="9" y="13" width="6" height="8" />
    </svg>
  ),
  reorder: (
    <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.6" strokeLinecap="round">
      <path d="M3 7 h13 l-3 -3 M3 7 l3 3" />
      <path d="M21 17 h-13 l3 3 M21 17 l-3 -3" />
    </svg>
  ),
  liquidate: (
    <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.6" strokeLinecap="round">
      <path d="M5 7 h14 l-1.5 12 a1 1 0 0 1 -1 1 h-9 a1 1 0 0 1 -1 -1 z" />
      <path d="M9 7 V5 a1 1 0 0 1 1 -1 h4 a1 1 0 0 1 1 1 v2" />
      <path d="M10 11 l4 5 M14 11 l-4 5" />
    </svg>
  ),
  produce: (
    <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.6" strokeLinejoin="round">
      <path d="M4 7 l8 -4 l8 4 l-8 4 z" />
      <path d="M4 7 v10 l8 4 v-10" />
      <path d="M20 7 v10 l-8 4" />
    </svg>
  ),
  receive: (
    <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.6" strokeLinejoin="round">
      <path d="M3 8 l9 -5 l9 5 v8 l-9 5 l-9 -5 z" />
      <path d="M3 8 l9 5 l9 -5 M12 13 v8" />
      <path d="M8 19 l2 2 l4 -4" />
    </svg>
  ),
  return: (
    <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.6" strokeLinecap="round">
      <path d="M9 14 L4 14 L4 9" />
      <path d="M4 14 a8 8 0 1 0 2 -6" />
    </svg>
  ),
};

const OPS_ACTIONS: Array<{ id: string; page: BridgePage; title: string; desc: string; cap: string }> = [
  { id: "new-item", page: "new-item", title: "New Item", desc: "Create a SKU — stocked, composed, or made-to-order.", cap: "Single or batch" },
  { id: "add-category", page: "add-category", title: "Add Category", desc: "Organize SKUs with an auto-classify rule.", cap: "Capital share read" },
  { id: "add-supplier", page: "add-supplier", title: "Add Supplier", desc: "New vendor — lead time, terms, country.", cap: "Dependency read" },
  { id: "reorder", page: "reorder", title: "Reorder", desc: "Place a PO — buy / hold / wait verdict and cash impact.", cap: "The verb spine" },
  { id: "liquidate", page: "liquidate", title: "Liquidate", desc: "Clear trapped capital from slow or dead stock.", cap: "Free cash" },
  { id: "produce", page: "produce", title: "Produce", desc: "Build composed SKUs from components.", cap: "Consumes stock" },
  { id: "receive", page: "receive", title: "Receive & Reconcile", desc: "Confirm what arrived vs the PO, capture real costs.", cap: "Keeps CM1 honest" },
  { id: "return", page: "return", title: "Process Return", desc: "Restock, write off, refund — and catch the pattern.", cap: "Return as signal" },
];

export function BridgeHome() {
  const { setPage } = useBridge();
  const [expanded, setExpanded] = useState(false);
  const [sent, setSent] = useState<string | null>(null);

  const flashSent = (key: string) => {
    setSent(key);
    setTimeout(() => setSent(null), 1500);
  };

  return (
    <div className="bridge-content">
      <div className="bridge-page-head">
        <div className="bridge-page-head-icon">
          <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="square">
            <rect x="3" y="3" width="8" height="8" />
            <rect x="13" y="3" width="8" height="8" />
            <rect x="3" y="13" width="8" height="8" />
            <rect x="13" y="13" width="8" height="8" />
          </svg>
        </div>
        <div>
          <div className="bridge-page-head-title">Operations Bridge</div>
          <div className="bridge-page-head-sub">
            Inventory, suppliers, purchase orders, and receiving.
          </div>
        </div>
      </div>

      {/* AI Strip */}
      <div className={`bridge-ai-strip${expanded ? " expanded" : ""}`}>
        <div className="bridge-ai-strip-head">
          <div className="bridge-ai-strip-label">
            <div className="m-mark">M</div>
            Operations AI · {opsBridgeMeta.pending} Pending
          </div>
          <div className="bridge-ai-strip-meta">
            <span>
              <span className="dot" />
              {opsBridgeMeta.confidence}
            </span>
            <span>{opsBridgeMeta.sources}</span>
            <span>{opsBridgeMeta.synced}</span>
          </div>
        </div>

        <div className="bridge-ai-strip-cards">
          {opsBridgeCards.map((c, i) => (
            <div
              key={i}
              className="bridge-ai-card"
              style={{ ["--accent" as string]: c.accent } as React.CSSProperties}
            >
              <div className="bridge-ai-card-tag">{c.tag}</div>
              <div className="bridge-ai-card-title">{c.title}</div>
              <div className="bridge-ai-card-body">{c.body}</div>
              <div className="bridge-ai-card-actions">
                <div className="bridge-ai-card-meta">
                  <span className={`bridge-risk-badge${RISK_CLASS[c.risk]}`}>
                    {c.riskLabel}
                  </span>
                </div>
                <div className="bridge-ai-card-buttons">
                  <button className="bridge-btn-got" type="button">
                    Snooze
                  </button>
                  <button
                    className={`bridge-btn-bridge${sent === c.exec ? " sent" : ""}`}
                    type="button"
                    onClick={() => flashSent(c.exec)}
                  >
                    {sent === c.exec ? "Sent ✓" : c.cta}
                  </button>
                </div>
              </div>
            </div>
          ))}
        </div>

        <div className="bridge-ai-strip-extra">
          {opsBridgeRows.map((r, i) => (
            <div
              key={i}
              className="bridge-ai-row"
              style={{ ["--accent" as string]: r.accent } as React.CSSProperties}
            >
              <div className="bridge-ai-row-tag">{r.tag}</div>
              <div className="bridge-ai-row-body">
                <div className="bridge-ai-row-title">{r.title}</div>
                <div className="bridge-ai-row-meta">
                  <span className={`bridge-risk-badge${RISK_CLASS[r.risk]}`}>
                    {r.riskLabel}
                  </span>
                </div>
              </div>
              <div className="bridge-ai-row-buttons">
                <button className="bridge-btn-got" type="button">
                  {r.risk === "low" && (r.exec.includes("dispatch") || r.exec.includes("courier"))
                    ? "Got it"
                    : "Snooze"}
                </button>
                <button
                  className={`bridge-btn-bridge${sent === r.exec ? " sent" : ""}`}
                  type="button"
                  onClick={() => flashSent(r.exec)}
                >
                  {sent === r.exec ? "Sent ✓" : r.cta}
                </button>
              </div>
            </div>
          ))}
        </div>

        <div className="bridge-ai-strip-showmore">
          <div className="bridge-ai-strip-showmore-text">
            <b>{opsBridgeMeta.shownTop}</b> of <b>{opsBridgeMeta.pending}</b> shown · sorted by priority
          </div>
          <button
            className="bridge-btn-showmore"
            type="button"
            onClick={() => setExpanded((v) => !v)}
          >
            <span className="label">
              {expanded ? "Hide" : `Show all ${opsBridgeMeta.pending - opsBridgeMeta.shownTop} more`}
            </span>
            <span className="arrow">⌄</span>
          </button>
        </div>
      </div>

      {/* Quick Actions grid */}
      <div className="bridge-actions-section">
        <div className="bridge-section-head">
          <div className="bridge-section-head-title">
            <span>Quick Actions</span>
          </div>
        </div>
        <div className="bridge-actions-grid">
          {OPS_ACTIONS.map((a) => (
            <button
              key={a.id}
              className="bridge-action-card"
              type="button"
              onClick={() => setPage(a.page)}
            >
              <div className="bridge-action-card-icon">{ACTION_ICONS[a.id]}</div>
              <div className="bridge-action-title">{a.title}</div>
              <div className="bridge-action-desc">{a.desc}</div>
              <div className="bridge-action-cap">{a.cap}</div>
            </button>
          ))}
        </div>
      </div>
    </div>
  );
}
