/**
 * Data for the Finance Bridge home surface.
 *
 *  - 3 top AI cards (the prominent grid)
 *  - 5 AI rows that appear when "Show all 5 more" is expanded
 *  - 6 Quick Actions verb cards (Classify, Approve Payment, Log Entry, …)
 *
 * Ported verbatim (copy + accents) from
 * /Users/mac/Downloads/MAGELLAN UX/Bridge/Finance/magellan-finance-home.html
 * The six surfaces follow the Finance model spec §8; see use-bridge.tsx.
 *
 * Mirrors the shape of ops-bridge-data.ts, plus a per-item `dismiss` label
 * (the Finance home varies the left button: Snooze / Hold / Got it).
 */

export type RiskLevel = "low" | "medium" | "high";

export interface FinanceAICard {
  /** CSS color string — drives the left accent + tag color (set inline as --accent) */
  accent: string;
  tag: string;
  title: string;
  body: string;
  riskLabel: string;
  risk: RiskLevel;
  /** Left (quiet) button label — Snooze / Hold / Got it */
  dismiss: string;
  /** Primary Bridge button label */
  cta: string;
  /** action key (for future drawer routing) */
  exec: string;
}

export interface FinanceAIRow {
  accent: string;
  tag: string;
  title: string;
  riskLabel: string;
  risk: RiskLevel;
  dismiss: string;
  cta: string;
  exec: string;
}

