"use client";

/* Dept Bridge home — /bridge/[dept]. Renders the room's home surface. */

import { useParams } from "next/navigation";
import { BridgeHome } from "@/features/bridge/components/BridgeHome";
import { BridgeFinanceHome } from "@/features/bridge/components/BridgeFinanceHome";

function DeptHomeStub({ dept }: { dept: string }) {
  const label = dept.charAt(0).toUpperCase() + dept.slice(1);
  return (
    <div className="bridge-content">
      <div className="bridge-page-head">
        <div className="bridge-page-head-icon">
          <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
            <circle cx="12" cy="12" r="9" />
            <path d="M12 7v6M12 17h.01" />
          </svg>
        </div>
        <div>
          <div className="bridge-page-head-title">{label} Bridge</div>
          <div className="bridge-page-head-sub">This room&rsquo;s Bridge isn&rsquo;t built yet — check back soon.</div>
        </div>
      </div>
      <div className="bridge-stub">
        <p>Coming soon. For now, use the Operations or Finance Bridge.</p>
      </div>
    </div>
  );
}

export default function DeptBridgeHome() {
  const { dept } = useParams();
  const d = String(dept);
  if (d === "finance") return <BridgeFinanceHome />;
  if (d === "ops") return <BridgeHome />;
  return <DeptHomeStub dept={d} />;
}
