export type RiskLevel = "low" | "medium" | "high";

export interface BridgeAICard {
  /** CSS color string (e.g. var(--d-ops), #3fb68a) — drives the left accent + tag color */
  accent: string;
  tag: string;
  title: string;
  body: string;
  riskLabel: string;
  risk: RiskLevel;
  /** What the primary Bridge button says */
  cta: string;
  /** action key (for future drawer routing) */
  exec: string;
}

export interface BridgeAIRow {
  accent: string;
  tag: string;
  title: string;
  riskLabel: string;
  risk: RiskLevel;
  cta: string;
  exec: string;
}

export interface BridgeAction {
  id: string;
  title: string;
  desc: string;
  cap: string;
  icon: React.ReactNode;
}

