"use client";

/* ════════════════════════════════════════════════════════════════════════
   BridgeFinanceHome — the Finance Bridge home surface.
   AI strip (3 cards + 5 expandable rows) + Quick Actions grid (6 verbs).

   Same shell + CSS as the Operations home (BridgeHome); Finance content and
   the green theme come from --dept-active (set on .bridge-overlay[data-dept]).
   The 6 verbs map 1:1 to the Finance subnav (Record / Review / Period).
   ════════════════════════════════════════════════════════════════════════ */

import { useState } from "react";
import { useBridge, type BridgePage } from "@/features/bridge/hooks/use-bridge";
import {
  financeBridgeCards,
  financeBridgeRows,
  financeBridgeMeta,
  financeBridgeState,
  financeTierLabel,
  type RiskLevel,
} from "@/features/finance/api/finance-bridge-data";

const RISK_CLASS: Record<RiskLevel, string> = {
  low: "",
  medium: " med",
  high: " high",
};

/* ─────────────── Quick Action icons (from the finance-home template) ─────────────── */
const ACTION_ICONS: Record<string, React.ReactNode> = {
  classify: (
    <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.6" strokeLinecap="round" strokeLinejoin="round">
      <path d="M3 7 h18 M3 12 h18 M3 17 h11" />
      <path d="M17 15 l2 2 l3 -3.5" />
    </svg>
  ),
  "approve-payment": (
    <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.6" strokeLinecap="round" strokeLinejoin="round">
      <circle cx="12" cy="12" r="9" />
      <path d="M8 12 l2.5 2.5 L16 9" />
    </svg>
  ),
  "log-entry": (
    <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.6" strokeLinecap="round" strokeLinejoin="round">
      <path d="M5 4 h14 v16 h-14 z" />
      <path d="M8 9 h8 M8 13 h8 M8 17 h4" />
    </svg>
  ),
  "recurring-cost": (
    <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.6" strokeLinecap="round" strokeLinejoin="round">
      <path d="M4 8 a8 8 0 0 1 14 -3 l2 2" />
      <path d="M20 4 v4 h-4" />
      <path d="M20 16 a8 8 0 0 1 -14 3 l-2 -2" />
      <path d="M4 20 v-4 h4" />
    </svg>
  ),
  reconcile: (
    <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.6" strokeLinecap="round" strokeLinejoin="round">
      <path d="M4 7 h7 M4 7 l2 -2 M4 7 l2 2" />
      <path d="M20 17 h-7 M20 17 l-2 -2 M20 17 l-2 2" />
      <path d="M11 7 a5 5 0 0 1 5 5 M13 17 a5 5 0 0 1 -5 -5" />
    </svg>
  ),
  "close-month": (
    <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.6" strokeLinecap="round" strokeLinejoin="round">
      <rect x="3" y="4" width="18" height="17" rx="1" />
      <path d="M3 9 h18 M8 2 v4 M16 2 v4" />
      <path d="M8 14 l2.5 2.5 L16 11" />
    </svg>
  ),
};

const FINANCE_ACTIONS: Array<{ id: string; page: BridgePage; title: string; desc: string; cap: string }> = [
  { id: "classify", page: "classify", title: "Classify Transactions", desc: "Assign uncategorized transactions to cost categories.", cap: "Batch · daily" },
  { id: "approve-payment", page: "approve-payment", title: "Approve Payment", desc: "Approve, schedule or hold an outflow — with a cash read.", cap: "Money out" },
  { id: "log-entry", page: "log-entry", title: "Log Entry", desc: "Record an inflow or outflow into the ledger.", cap: "Manual or chargeback" },
  { id: "recurring-cost", page: "recurring-cost", title: "Recurring Cost", desc: "Add, pause, cancel or renegotiate a recurring charge.", cap: "Annualized impact" },
  { id: "reconcile", page: "reconcile", title: "Reconcile", desc: "Match records to receipts and statements; resolve gaps.", cap: "Keeps books honest" },
  { id: "close-month", page: "close-month", title: "Close Month", desc: "Run the close checklist and commit the period.", cap: "Orchestrates the rest" },
];

export function BridgeFinanceHome() {
  const { setPage } = useBridge();
  const [expanded, setExpanded] = useState(false);
  const [sent, setSent] = useState<string | null>(null);

  const flashSent = (key: string) => {
    setSent(key);
    setTimeout(() => setSent(null), 1500);
  };

  return (
    <div className="bridge-content">
      <div className="bridge-page-head">
        <div className="bridge-page-head-icon">
          <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
            <path d="M4 3 h12 a2 2 0 0 1 2 2 v16 l-3 -2 -3 2 -3 -2 -3 2 z" />
            <path d="M8 8 h6 M8 12 h6" />
          </svg>
        </div>
        <div>
          <div className="bridge-page-head-title">Finance Bridge</div>
          <div className="bridge-page-head-sub">
            Classify, approve, record, reconcile — and close the month.
          </div>
        </div>
      </div>

      {/* Month-headline status-tier panel — Magellan ahead, accountant catches up */}
      <div className="bridge-fin-state">
        <div className="bridge-fin-state-main">
          <div className="bridge-fin-state-head">{financeBridgeState.head}</div>
          <div className="bridge-fin-state-num">
            {financeBridgeState.value}
            <span className="est">{financeBridgeState.valueSub}</span>
          </div>
          <div className="bridge-fin-state-line">
            {financeBridgeState.line.map((p, i) => (p.b ? <b key={i}>{p.t}</b> : <span key={i}>{p.t}</span>))}
          </div>
          <div className="bridge-fin-prog">
            <div className="bridge-fin-prog-track">
              {financeBridgeState.progress.map((s, i) => (
                <div key={i} className={`bridge-fin-prog-seg ${s.tier}`} style={{ width: `${s.pct}%` }} />
              ))}
            </div>
            <div className="bridge-fin-prog-legend">
              {financeBridgeState.legend.map((t) => (
                <span key={t} className="bridge-tier-pill">
                  <span className={`bridge-tier-dot ${t}`} />
                  {financeTierLabel[t]}
                </span>
              ))}
            </div>
          </div>
        </div>
        <div className="bridge-fin-state-tiers">
          {financeBridgeState.tiers.map((r) => (
            <div key={r.tier} className="bridge-fin-tier-row">
              <span className="lbl">
                <span className={`bridge-tier-dot ${r.tier}`} />
                {r.label}
              </span>
              <span className="val">{r.value}</span>
            </div>
          ))}
        </div>
      </div>

      {/* AI Strip */}
      <div className={`bridge-ai-strip${expanded ? " expanded" : ""}`}>
        <div className="bridge-ai-strip-head">
          <div className="bridge-ai-strip-label">
            <div className="m-mark">M</div>
            Finance AI · {financeBridgeMeta.pending} Pending
          </div>
          <div className="bridge-ai-strip-meta">
            <span>
              <span className="dot" />
              {financeBridgeMeta.confidence}
            </span>
            <span>{financeBridgeMeta.sources}</span>
            <span>{financeBridgeMeta.synced}</span>
          </div>
        </div>

        <div className="bridge-ai-strip-cards">
          {financeBridgeCards.map((c, i) => (
            <div
              key={i}
              className="bridge-ai-card"
              style={{ ["--accent" as string]: c.accent } as React.CSSProperties}
            >
              <div className="bridge-ai-card-tag">{c.tag}</div>
              <div className="bridge-ai-card-title">{c.title}</div>
              <div className="bridge-ai-card-body">{c.body}</div>
              <div className="bridge-ai-card-actions">
                <div className="bridge-ai-card-meta">
                  <span className={`bridge-risk-badge${RISK_CLASS[c.risk]}`}>
                    {c.riskLabel}
                  </span>
                </div>
                <div className="bridge-ai-card-buttons">
                  <button className="bridge-btn-got" type="button">
                    {c.dismiss}
                  </button>
                  <button
                    className={`bridge-btn-bridge${sent === c.exec ? " sent" : ""}`}
                    type="button"
                    onClick={() => flashSent(c.exec)}
                  >
                    {sent === c.exec ? "Sent ✓" : c.cta}
                  </button>
                </div>
              </div>
            </div>
          ))}
        </div>

        <div className="bridge-ai-strip-extra">
          {financeBridgeRows.map((r, i) => (
            <div
              key={i}
              className="bridge-ai-row"
              style={{ ["--accent" as string]: r.accent } as React.CSSProperties}
            >
              <div className="bridge-ai-row-tag">{r.tag}</div>
              <div className="bridge-ai-row-body">
                <div className="bridge-ai-row-title">{r.title}</div>
                <div className="bridge-ai-row-meta">
                  <span className={`bridge-risk-badge${RISK_CLASS[r.risk]}`}>
                    {r.riskLabel}
                  </span>
                </div>
              </div>
              <div className="bridge-ai-row-buttons">
                <button className="bridge-btn-got" type="button">
                  {r.dismiss}
                </button>
                <button
                  className={`bridge-btn-bridge${sent === r.exec ? " sent" : ""}`}
                  type="button"
                  onClick={() => flashSent(r.exec)}
                >
                  {sent === r.exec ? "Sent ✓" : r.cta}
                </button>
              </div>
            </div>
          ))}
        </div>

        <div className="bridge-ai-strip-showmore">
          <div className="bridge-ai-strip-showmore-text">
            <b>{financeBridgeMeta.shownTop}</b> of <b>{financeBridgeMeta.pending}</b> shown · sorted by priority
          </div>
          <button
            className="bridge-btn-showmore"
            type="button"
            onClick={() => setExpanded((v) => !v)}
          >
            <span className="label">
              {expanded ? "Hide" : `Show all ${financeBridgeMeta.pending - financeBridgeMeta.shownTop} more`}
            </span>
            <span className="arrow">⌄</span>
          </button>
        </div>
      </div>

      {/* Quick Actions grid */}
      <div className="bridge-actions-section">
        <div className="bridge-section-head">
          <div className="bridge-section-head-title">
            <span>Quick Actions</span>
          </div>
        </div>
        <div className="bridge-actions-grid">
          {FINANCE_ACTIONS.map((a) => (
            <button
              key={a.id}
              className="bridge-action-card"
              type="button"
              onClick={() => setPage(a.page)}
            >
              <div className="bridge-action-card-icon">{ACTION_ICONS[a.id]}</div>
              <div className="bridge-action-title">{a.title}</div>
              <div className="bridge-action-desc">{a.desc}</div>
              <div className="bridge-action-cap">{a.cap}</div>
            </button>
          ))}
        </div>
      </div>
    </div>
  );
}
